verilog_template:
module not_gate(input A, output Y);
  not g1(Y, A);
endmodule

module nor_gate(input A, input B, output Y);
  nor g1(Y, A, B);
endmodule

module or_gate(input A, input B, output Y);
  or g1(Y, A, B);
endmodule

module nand_gate(input A, input B, output Y);
  nand g1(Y, A, B);
endmodule

module xor_gate(input A, input B, output Y);
  xor g1(Y, A, B);
endmodule

module xnor_gate(input A, input B, output Y);
  xnor g1(Y, A, B);
endmodule

module toggle_switch(input S, input R, output Q, output Qbar);
  nor g1(Q, R, Qbar);
  nor g2(Qbar, S, Q);
endmodule

module repressilator(output A, output B, output C);
  not g1(A, C);
  not g2(B, A);
  not g3(C, B);
endmodule

module coherent_ffl(input X, output Z);
  wire Y;
  assign Y = X; // Acts as a delay channel
  and g1(Z, X, Y);
endmodule

module incoherent_ffl(input X, output Z);
  wire Y;
  not g1(Y, X); // Y is intermediate repressor
  and g2(Z, X, Y);
endmodule

module threshold_gate(input A, output Y);
  wire w1;
  not g1(w1, A);
  not g2(Y, w1); // Double inversion acts as buffer with sharp threshold
endmodule

module pulse_generator(input In, output Out);
  wire delay_repressor;
  not g1(delay_repressor, In);
  and g2(Out, In, delay_repressor);
endmodule

module band_pass_filter(input In, output Out);
  wire low_pass, high_pass_n;
  assign low_pass = In;        // Low threshold activation pathway
  not g1(high_pass_n, In);     // High threshold repression pathway
  and g2(Out, low_pass, high_pass_n);
endmodule
